mapper.select:
SELECT r.id, r.reporter_id AS reporterId, reporter.username AS reporterName, reporter.user_avatar AS reporterAvatar, r.target_type AS targetType, r.target_id AS targetId, CASE WHEN r.target_type = 1 THEN p.title WHEN r.target_type = 2 THEN CAST(c.content AS CHAR) END AS targetContent, CASE WHEN r.target_type = 1 THEN p.user_id WHEN r.target_type = 2 THEN c.user_id END AS targetAuthorId, CASE WHEN r.target_type = 1 THEN u1.username WHEN r.target_type = 2 THEN u2.username END AS targetAuthorName, r.reason_type AS reasonType, r.reason_detail AS reasonDetail, r.status, r.handler_id AS handlerId, handler.username AS handlerName, r.handle_result AS handleResult, r.handle_time AS handleTime, r.create_time AS createTime, rs.report_count AS reportCount FROM tb_report r LEFT JOIN tb_user reporter ON r.reporter_id = reporter.id LEFT JOIN tb_user handler ON r.handler_id = handler.id LEFT JOIN tb_community_post p ON r.target_type = 1 AND r.target_id = p.id LEFT JOIN tb_comment c ON r.target_type = 2 AND r.target_id = c.id LEFT JOIN tb_user u1 ON r.target_type = 1 AND p.user_id = u1.id LEFT JOIN tb_user u2 ON r.target_type = 2 AND c.user_id = u2.id LEFT JOIN tb_report_stats rs ON r.target_type = rs.target_type AND r.target_id = rs.target_id
AND r.status = #{status}
AND r.target_type = #{targetType}
ORDER BY r.create_time DESC
